// LazusAI inbound handler — one parameterized instance for every client.
// Pipeline: voice transcription -> load config -> RAG context -> build prompt
// -> NIM (DeepSeek->Kimi->GLM->Mistral) -> escalation check -> reply via
// BlueBubbles -> log turn. All endpoints are local (no external AI APIs).

const http = this.helpers.httpRequest;
const env = (k, d='') => ($env[k] ?? d);
const CORE = env('CORE_API_URL', 'http://127.0.0.1:8003').replace(/\/$/, '');
const NIM = env('NIM_BASE_URL', 'http://127.0.0.1:8000').replace(/\/$/, '');
const WHISPER = env('WHISPER_URL', 'http://127.0.0.1:8002').replace(/\/$/, '');
const BB = env('BLUEBUBBLES_URL', '').replace(/\/$/, '');
const BB_PW = env('BLUEBUBBLES_PASSWORD', '');
const KEY = env('LAZUSAI_CORE_KEY', '');
const hdr = { 'X-LazusAI-Key': KEY, 'Content-Type': 'application/json' };

const inItem = $input.first().json;
const clientId = (inItem.params && inItem.params.client_id) || inItem.client_id;
const body = inItem.body || inItem;
let messageText = body.message || '';
const sender = body.sender || '';
const chatGuid = body.chat_guid || '';

// 1. Voice note -> Whisper transcription.
if (body.voice_note) {
  const audio = (body.attachments || []).find(a => a.is_audio) || {};
  let url = audio.url || '';
  if (url.startsWith('/') && BB) url = BB + url;
  const tr = await http({ method: 'POST', url: WHISPER + '/transcribe',
    headers: hdr, body: { url, filename: audio.name || 'audio.m4a' }, json: true });
  messageText = (tr && tr.text) || messageText;
}

// 2. Load client config.
const cfg = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/config`, headers: hdr, json: true });
if (cfg.active === false) {
  return [{ json: { skipped: true, reason: 'inactive', client_id: clientId } }];
}

// 3. RAG: relevant business context + last 10 turns.
const feed = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/feed?limit=10`, headers: hdr, json: true });
const recent = (feed.turns || []).map(t => ({ role: t.role === 'assistant' ? 'assistant' : 'user', content: t.text }));

// Build a compact business-context block from config (services/pricing/hours/faqs).
// (ChromaDB also stores these as embeddings; the config-derived block keeps the
// prompt deterministic and SMS-fast.)
const ctxLines = [];
if (cfg.services && cfg.services.length) ctxLines.push('Services: ' + cfg.services.join(', '));
if (cfg.pricing) ctxLines.push('Pricing: ' + Object.entries(cfg.pricing).map(([k,v])=>`${k}: ${v}`).join('; '));
if (cfg.hours) ctxLines.push('Hours: ' + Object.entries(cfg.hours).map(([k,v])=>`${k} ${v}`).join('; '));
if (cfg.faqs) cfg.faqs.forEach(f => ctxLines.push(`FAQ — ${f.q} ${f.a}`));
const contextBlock = ctxLines.join('\n');

// 4. Build prompt: persona + business context as system, history, user msg.
const systemPrompt = `You are the iMessage assistant for ${cfg.business_name} (${cfg.industry}).\nPersonality & rules: ${cfg.ai_personality}\n\nBusiness context:\n${contextBlock}\n\nAnswer as the business. Be concise (SMS-length). If you cannot help, offer to have the owner follow up and capture the customer's name and contact details.`;
const messages = [{ role: 'system', content: systemPrompt }, ...recent, { role: 'user', content: messageText }];

// 5. NIM with fallback chain.
const chain = [
  env('NIM_MODEL_DEEPSEEK', 'deepseek-ai/deepseek-r1'),
  env('NIM_MODEL_KIMI', 'moonshotai/kimi-k2'),
  env('NIM_MODEL_GLM', 'zhipuai/glm-5.2'),
  env('NIM_MODEL_MISTRAL', 'mistralai/mistral-large')
];
let reply = '', usedModel = '';
for (const model of chain) {
  try {
    const r = await http({ method: 'POST', url: `${NIM}/v1/chat/completions`, headers: hdr,
      body: { model, messages, temperature: 0.4, max_tokens: 500 }, json: true });
    reply = (((r.choices||[])[0]||{}).message||{}).content || '';
    reply = reply.trim();
    if (reply) { usedModel = model; break; }
  } catch (e) { /* try next model */ }
}
if (!reply) reply = 'Thanks for your message! Someone from our team will get back to you shortly.';

// 6. Escalation keyword check.
const kws = (cfg.escalation_keywords || []).map(k => k.toLowerCase());
const hay = messageText.toLowerCase();
const escalated = kws.some(k => hay.includes(k));

// 7. Reply via BlueBubbles REST -> delivers over iMessage.
if (BB && chatGuid) {
  await http({ method: 'POST', url: `${BB}/api/v1/message/text`,
    qs: { password: BB_PW },
    body: { chatGuid, tempGuid: 'lazusai-' + Date.now(), message: reply, method: 'private-api' },
    json: true });
}

// 8. Log both turns to ChromaDB (via core API).
await http({ method: 'POST', url: `${CORE}/clients/${clientId}/turns`, headers: hdr,
  body: { role: 'user', text: messageText, sender }, json: true });
await http({ method: 'POST', url: `${CORE}/clients/${clientId}/turns`, headers: hdr,
  body: { role: 'assistant', text: reply, sender }, json: true });

return [{ json: { client_id: clientId, sender, message: messageText, reply,
  model: usedModel, escalated, voice_note: !!body.voice_note } }];
